package com.example.secondphone.security;
import org.springframework.security.core.userdetails.*;import org.springframework.stereotype.Service;import com.example.secondphone.entity.*;import com.example.secondphone.repository.MemberRepository;
@Service public class CustomUserDetailsService implements UserDetailsService{private final MemberRepository members;public CustomUserDetailsService(MemberRepository members){this.members=members;}@Override public UserDetails loadUserByUsername(String account){Member member=members.findByAccountIgnoreCaseOrEmailIgnoreCase(account,account).orElseThrow(()->new UsernameNotFoundException("帳號或密碼錯誤"));return User.withUsername(member.getAccount()).password(member.getPassword()).roles(member.getRoleEnum().name()).disabled(member.getStatusEnum()==MemberStatus.DISABLED).build();}}
